// Headless-screenshot target for the AI input. Renders Google Photorealistic
// 3D Tiles via CesiumJS at a tilted angle around the lat/lng. Cesium creates
// its WebGL context with `preserveDrawingBuffer: true` so headless Playwright
// captures the canvas correctly (Google Maps JS does not, hence Cesium).
//
// URL: /oblique?lat=...&lng=...&zoom=19&heading=0&tilt=60

'use client';

import dynamic from 'next/dynamic';

const ObliqueCesium = dynamic(() => import('./ObliqueCesium').then((m) => m.ObliqueCesium), {
  ssr: false,
});

export default function ObliquePage() {
  return <ObliqueCesium />;
}
---ObliqueCesium---
'use client';

import { useEffect, useRef } from 'react';
import { useSearchParams } from 'next/navigation';

export function ObliqueCesium() {
  const sp = useSearchParams();
  const lat = parseFloat(sp.get('lat') ?? '');
  const lng = parseFloat(sp.get('lng') ?? '');
  const zoom = parseFloat(sp.get('zoom') ?? '19');
  const headingDeg = parseFloat(sp.get('heading') ?? '0');
  const tiltDeg = parseFloat(sp.get('tilt') ?? '60');
  const ref = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
    const apiKey = process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY;
    if (!apiKey) return;
    const baseUrl = process.env.NEXT_PUBLIC_CESIUM_BASE_URL ?? '/cesium';

    let cancelled = false;
    let viewer: import('cesium').Viewer | null = null;

    (async () => {
      // Cesium reads window.CESIUM_BASE_URL once at first import.
      (window as unknown as { CESIUM_BASE_URL: string }).CESIUM_BASE_URL = baseUrl;
      // Inject widgets CSS (the bundler import causes Turbopack issues).
      if (!document.querySelector('link[data-cesium-widgets]')) {
        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = `${baseUrl}/Widgets/widgets.css`;
        link.setAttribute('data-cesium-widgets', '');
        document.head.appendChild(link);
      }

      const Cesium = await import('cesium');
      if (cancelled || !ref.current) return;

      viewer = new Cesium.Viewer(ref.current, {
        baseLayerPicker: false,
        geocoder: false,
        homeButton: false,
        sceneModePicker: false,
        navigationHelpButton: false,
        animation: false,
        timeline: false,
        fullscreenButton: false,
        infoBox: false,
        selectionIndicator: false,
        shouldAnimate: false,
        contextOptions: { webgl: { preserveDrawingBuffer: true } },
        baseLayer: false as unknown as import('cesium').ImageryLayer,
      });

      viewer.scene.skyBox.show = false;
      viewer.scene.skyAtmosphere.show = false;
      viewer.scene.sun.show = false;
      viewer.scene.moon.show = false;
      viewer.scene.fog.enabled = false;
      viewer.scene.globe.show = false;
      viewer.scene.backgroundColor = Cesium.Color.fromCssColorString('#ffffff');

      try {
        const tilesetUrl = `https://tile.googleapis.com/v1/3dtiles/root.json?key=${encodeURIComponent(apiKey)}`;
        const tileset = await Cesium.Cesium3DTileset.fromUrl(tilesetUrl, {
          showCreditsOnScreen: false,
          maximumScreenSpaceError: 6,
        });
        if (cancelled) {
          tileset.destroy();
          return;
        }
        viewer.scene.primitives.add(tileset);

        // Bird's-eye oblique: tight enough to see roof slope clearly.
        // pitch = -tiltDeg (60° below horizontal = steep oblique looking down)
        // range = 110m frames a single residential roof at high detail.
        const range = 110;
        const aim = Cesium.Cartesian3.fromDegrees(lng, lat, 65);
        viewer.camera.lookAtTransform(Cesium.Matrix4.IDENTITY);

