// piggyback on it so the screenshot logic isn't duplicated here.
async function fetchObliqueScreenshot(
  lat: number,
  lng: number,
  zoom: number,
  origin?: string,
): Promise<Buffer | null> {
  if (!origin) return null;
  const url = `${origin}/api/aerial?lat=${lat}&lng=${lng}&zoom=${zoom}&tilted=1`;
  const res = await fetch(url);
  if (!res.ok) return null;
  return Buffer.from(await res.arrayBuffer());
}

// Composites a small solid red disc with a white outline at the image centre.
// Mirrors the Static Maps `markers=color:red|size:tiny` pin so the Gemini
// prompts see a consistent visual anchor between top-down and oblique views.
async function overlayCenterPin(buf: Buffer, w: number, h: number): Promise<Buffer> {
  const sharp = (await import('sharp')).default;
  const r = 9;
  const cx = Math.round(w / 2);
  const cy = Math.round(h / 2);
  const svg = Buffer.from(
    `<svg xmlns="http://www.w3.org/2000/svg" width="${w}" height="${h}">` +
      `<circle cx="${cx}" cy="${cy}" r="${r + 2}" fill="#ffffff"/>` +
      `<circle cx="${cx}" cy="${cy}" r="${r}" fill="#ff1f1f"/>` +
      `</svg>`,
  );
  return await sharp(buf).composite([{ input: svg, top: 0, left: 0 }]).png().toBuffer();
}

